import { Toaster } from "@/components/ui/toaster"
import { QueryClientProvider } from '@tanstack/react-query'
import { queryClientInstance } from '@/lib/query-client'
import NavigationTracker from '@/lib/NavigationTracker'
import { pagesConfig } from './pages.config'
import { BrowserRouter as Router, Route, Routes } from 'react-router-dom';
import PageNotFound from './lib/PageNotFound';
import { AuthProvider, useAuth } from '@/lib/AuthContext';
import UserNotRegisteredError from '@/components/UserNotRegisteredError';
import Login from './pages/Login';
import { getAllowedPages } from '@/lib/roles';
import ErrorBoundary from '@/components/ErrorBoundary';

const { Pages, Layout, mainPage } = pagesConfig;
const mainPageKey = mainPage ?? Object.keys(Pages)[0];
const MainPage = mainPageKey ? Pages[mainPageKey] : <></>;

const LayoutWrapper = ({ children, currentPageName }) => Layout ?
  <Layout currentPageName={currentPageName}>{children}</Layout>
  : <>{children}</>;

// דפים ציבוריים — נגישים ללא כניסה
const PUBLIC_PAGES = ['WorkLogForm', 'SignChangeOrder'];

const AuthenticatedApp = () => {
  const { isLoadingAuth, isAuthenticated, user } = useAuth();

  // טוען — בודק סשן
  if (isLoadingAuth) {
    return (
      <div className="fixed inset-0 flex items-center justify-center" style={{ backgroundColor: "#F2EEE6" }}>
        <div className="w-8 h-8 border-4 border-[#D0C8BC] border-t-[#987F68] rounded-full animate-spin"></div>
      </div>
    );
  }

  // דף ציבורי — מאפשר גישה ללא כניסה
  const currentPath = window.location.pathname.replace('/', '');
  if (PUBLIC_PAGES.includes(currentPath)) {
    return (
      <Routes>
        {Object.entries(pagesConfig.Pages)
          .filter(([path]) => PUBLIC_PAGES.includes(path))
          .map(([path, Page]) => (
            <Route key={path} path={`/${path}`} element={<Page />} />
          ))}
      </Routes>
    );
  }

  // לא מחובר — מסך כניסה
  if (!isAuthenticated) {
    return <Login />;
  }

  // הרשאות — דפים מותרים לפי תפקיד
  const allowedPages = getAllowedPages(user?.email);
  const defaultPage = allowedPages.includes(mainPageKey) ? mainPageKey : allowedPages[0] || mainPageKey;
  const DefaultPageComponent = Pages[defaultPage] || MainPage;

  // Render the main app
  return (
    <Routes>
      <Route path="/" element={
        <LayoutWrapper currentPageName={defaultPage}>
          <DefaultPageComponent />
        </LayoutWrapper>
      } />
      {Object.entries(Pages).map(([path, Page]) => (
        <Route
          key={path}
          path={`/${path}`}
          element={
            allowedPages.includes(path) ? (
              <LayoutWrapper currentPageName={path}>
                <Page />
              </LayoutWrapper>
            ) : (
              <LayoutWrapper currentPageName={defaultPage}>
                <DefaultPageComponent />
              </LayoutWrapper>
            )
          }
        />
      ))}
      <Route path="*" element={<PageNotFound />} />
    </Routes>
  );
};


function App() {

  return (
    <ErrorBoundary>
      <AuthProvider>
        <QueryClientProvider client={queryClientInstance}>
          <Router>
            <NavigationTracker />
            <ErrorBoundary>
              <AuthenticatedApp />
            </ErrorBoundary>
          </Router>
          <Toaster />
        </QueryClientProvider>
      </AuthProvider>
    </ErrorBoundary>
  )
}

export default App

