import React from 'react'
import ReactDOM from 'react-dom/client'
import App from '@/App.jsx'
import '@/index.css'

class ErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false, error: null };
  }
  static getDerivedStateFromError(error) {
    return { hasError: true, error };
  }
  render() {
    if (this.state.hasError) {
      return React.createElement('div', {
        dir: 'rtl',
        style: { padding: '40px', fontFamily: 'sans-serif', textAlign: 'center' }
      },
        React.createElement('h1', { style: { color: '#C62828' } }, 'שגיאה בטעינת האפליקציה'),
        React.createElement('pre', {
          style: { background: '#f5f5f5', padding: '20px', borderRadius: '12px', textAlign: 'left', overflow: 'auto', marginTop: '20px', fontSize: '13px' }
        }, String(this.state.error?.stack || this.state.error))
      );
    }
    return this.props.children;
  }
}

ReactDOM.createRoot(document.getElementById('root')).render(
  <ErrorBoundary>
    <App />
  </ErrorBoundary>
)

